  ('about', 'beliefs.item2.body', 'We believe the Bible is God''s inspired, authoritative, and trustworthy rule of faith and practice.', 'richtext'),
  ('about', 'beliefs.item2.title', 'Authority of Scripture', 'text'),
  ('about', 'beliefs.item3.body', 'We believe in the power of prayer. The ministries and activities of our church are characterized by a reliance on personal and corporate prayer.', 'richtext'),
