  ('event.weekly_bible_study_group', 'body.p1', 'Weekly Bible Study', 'richtext'),
  ('event.weekly_bible_study_group', 'body.p2', 'Join usEvery Thursday night at 7:00 PMfor an uplifting time of fellowship and study at theMississauga Church of God(inside theSalvation Army Erin Mills Church).', 'richtext'),
  ('event.weekly_bible_study_group', 'body.p3', 'Our Bible study gatherings are a chance to dive deeper into God’s Word, grow in faith, and build lasting connections with others. Whether you are new to studying the Bible or have been walking with Christ for years, you’ll find encouragement, insight, and a welcoming community.', 'richtext'),
  ('event.weekly_bible_study_group', 'body.p4', '📍Location:Salvation Army Erin Mills Church – Home of Mississauga Church of God🕖Time:Thursdays @ 7:00 PM', 'richtext'),
  ('event.weekly_bible_study_group', 'body.p5', 'Come ready to learn, share, and be strengthened in your spiritual walk. Everyone is welcome!', 'richtext'),
  ('event.weekly_bible_study_group', 'hero.title', 'Weekly Bible Study Group', 'text'),
  ('event.weekly_bible_study_group', 'meta.description', '', 'text'),
  ('event.weekly_bible_study_group', 'meta.title', 'Weekly Bible Study Group', 'text'),
  ('event.young_adults_connect', 'body.p1', 'You are warmly invited to attend ourYeshua Sunday Service, hosted byBishop H. O. Wilson, held every4th Sunday of the month at 1:00 PMat theMississauga Church of God(located inside the Salvation Army Erin Mills Church, 2460 The Collegeway, Mississauga, ON).', 'richtext'),
  ('event.young_adults_connect', 'body.p2', 'This sacred gathering is dedicated to exalting the name of our Lord and Savior, Yeshua the Messiah, through worship, the ministry of the Word, and the fellowship of believers. We welcome all who desire to draw nearer to Christ, be strengthened in faith, and experience the power of God’s presence.', 'richtext'),
  ('event.young_adults_connect', 'body.p3', 'We extend this invitation to you, your family, and your friends to join us in lifting high the name of Yeshua. May this service be a time of spiritual renewal and blessing for all who attend.', 'richtext'),
  ('event.young_adults_connect', 'hero.title', 'Yeshua Sunday Service', 'text'),
