  ('sermon.do_not_lose_heart_your_future_in_christ_is_beyond_all_comparison', 'cta.2.href', 'https://twitter.com/intent/tweet?url=https%3A%2F%2Fydministries.ca%2Fhow-to-develop-a-habit-of-worship%2F&text=We%20often%20talk%20about%20developing%20a%20daily%20habit%20of%20prayer%20and%20reading%20God’s%20Word.%20But%20what%20about%20worship?%20How%20do%20we%20practically%20incorporate%20worship%20into%20our%20busy%20schedules%20and%20develop%20a%20habit%20of%20worship?', 'url'),
  ('sermon.do_not_lose_heart_your_future_in_christ_is_beyond_all_comparison', 'cta.2.label', '', 'text'),
  ('sermon.do_not_lose_heart_your_future_in_christ_is_beyond_all_comparison', 'cta.3.href', 'https://www.linkedin.com/shareArticle?mini=true&url=https%3A%2F%2Fydministries.ca%2Fhow-to-develop-a-habit-of-worship%2F&title=How%20to%20Develop%20a%20Habit%20of%20Worship&summary=We%20often%20talk%20about%20developing%20a%20daily%20habit%20of%20prayer%20and%20reading%20God’s%20Word.%20But%20what%20about%20worship?%20How%20do%20we%20practically%20incorporate%20worship%20into%20our%20busy%20schedules%20and%20develop%20a%20habit%20of%20worship?&source=https%3A%2F%2Fydministries.ca%2Fhow-to-develop-a-habit-of-worship%2F', 'url'),
