  ('sermon.experiencing_the_freedom_of_gods_presence', 'sections.h3_2', 'We Must Choose to Obtain', 'text'),
  ('sermon.experiencing_the_freedom_of_gods_presence', 'sections.h3_3', 'The Heart of the True Father', 'text'),
